55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const CURSED_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const FIRST_INSURANCE_RATE = 0.1;
62	const LOYALTY_DISCOUNT_RATE = 0.2;
63	const LOYALTY_YEARS_THRESHOLD = 2;
64	const FOLLOWUP_DISCOUNT_RATE = 0.15;
65	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
66	  sword: 100,
67	  amulet: 60,
68	  staff: 80,
69	  potion: 40,
70	  rune: 25,
71	  moonstone: 25,
72	};
73	
74	const basePremium = (item: Item): number =>
75	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
76	
77	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
78	
79	const groupByType = (items: Item[]): Map<string, Item[]> => {
80	  const groups = new Map<string, Item[]>();
81	  for (const item of items) {
82	    const existing = groups.get(item.type) ?? [];
83	    existing.push(item);
84	    groups.set(item.type, existing);
85	  }
86	  return groups;
87	};
88	
89	const sumBasePremiums = (items: Item[]): number =>
90	  items.reduce((sum, item) => sum + basePremium(item), 0);
91	
92	const isCompleteComponentBlock = (type: string, group: Item[]): boolean =>
93	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type);
94	
95	const groupTotal = (type: string, group: Item[]): number =>
96	  isCompleteComponentBlock(type, group)
97	    ? COMPONENT_BLOCK_PRICE
98	    : sumBasePremiums(group);
99	
100	const policyBase = (items: Item[]): number =>
101	  Array.from(groupByType(items)).reduce(
102	    (sum, [type, group]) => sum + groupTotal(type, group),
103	    0,
104	  );
105	
106	const perItemSurcharge = (
107	  items: Item[],
108	  predicate: (item: Item) => boolean,
109	  rate: number,
110	): number =>
111	  items.reduce(
112	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
113	    0,
114	  );
115	
116	const isCursed = (item: Item): boolean => item.cursed === true;
117	
118	const isHighlyEnchanted = (item: Item): boolean =>
119	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
120	
121	const firstInsuranceSurcharge = (base: number): number =>
122	  base * FIRST_INSURANCE_RATE;
123	
124	const loyaltyDiscount = (base: number, customer: Customer): number =>
125	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
126	    ? base * LOYALTY_DISCOUNT_RATE
127	    : 0;
128	
129	const followupDiscount = (base: number, quoteIndex: number): number =>
130	  quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
131	
132	const quotePremium = (
133	  items: Item[],
134	  customer: Customer,
135	  quoteIndex: number,
136	): number => {
137	  const base = policyBase(items);
138	  const modifiedBase =
139	    base +
140	    perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE) +
141	    perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE) +
142	    firstInsuranceSurcharge(base) -
143	    loyaltyDiscount(base, customer) -
144	    followupDiscount(base, quoteIndex);
145	  return Math.ceil(modifiedBase) + PROCESSING_FEE;
146	};
