148	export const processScenario = (scenario: Scenario): ScenarioOutput => {
149	  let quoteCount = 0;
150	  const results: StepResult[] = scenario.steps.map((step) => {
151	    if (step.op === "quote") {
152	      const result = {
153	        premium: quotePremium(step.items, scenario.customer, quoteCount),
154	      };
155	      quoteCount += 1;
156	      return result;
157	    }
158	    return { payout: 0, remainingCap: 0 };
159	  });
160	  return { results };
161	};
