const processQuote = (
  step: QuoteStep,
  customer: Customer,
  quoteIndex: number,
): QuoteResult => ({
  premium: quotePremium(step.items, customer, quoteIndex),
});

const processClaim = (_step: ClaimStep): ClaimResult => ({
  payout: 0,
  remainingCap: 0,
});

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  let quoteCount = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return processQuote(step, scenario.customer, quoteCount++);
    }
    return processClaim(step);
  });
  return { results };
};
